use std::fs::File;
use std::io::{self, BufReader, BufRead};

fn main() -> io::Result<()> {
    let args: Vec<String> = std::env::args().collect();
    if args.len() < 2 {
        println!("Usage: {} <file1> [file2] ...", args[0]);
        return Ok(());
    }

    let files_to_process = &args[1..];
    let mut results = String::new();

    for file_path in files_to_process {
        println!("Processing {}...", file_path);
        let file = File::open(file_path)?;
        let reader = BufReader::new(file);

        for line in reader.lines() {
            let line = line?;
            if !line.contains(":ERROR:") && !line.contains("DEBUG") && !line.contains("INFO") {
                if line.contains("192.168.1.") {
                    results.push_str(&format!("{}: {}n", file_path, line));
                }
            }
        }
    }

    println!("n--- Aggregated Results ---n{}", results);
    Ok(())
}

use std::collections::HashMap;
use std::fs::File;
use std::io::{self, Read};

struct ConfigRecord {
    path: String,
    is_valid: bool,
    error: Option<String>,
}

fn load_and_validate(path: &str) -> Result<Vec<u8>, io::Error> {
    let mut file = File::open(path)?;
    let mut buffer = Vec::new();
    file.read_to_end(&mut buffer)?; 
    Ok(buffer)
}

fn process_config(record: &str) -> ConfigRecord {
    match load_and_validate(record) {
        Ok(_) => ConfigRecord { path: record.to_string(), is_valid: true, error: None },
        Err(e) => ConfigRecord { path: record.to_string(), is_valid: false, error: Some(e.to_string()) }
    }
}

fn main() -> Result<(), io::Error> {
    let file_paths = vec!["data/good_config.txt", "data/bad_file.bin", "data/another_good.cfg"];
    let mut results: HashMap<String, ConfigRecord> = HashMap::new();

    for path in file_paths {
        let record = process_config(path);
        results.insert(record.path.clone(), record);
    }

    println!("n--- Validation Summary ---");
    for (key, record) in results.iter() {
        if record.is_valid {
            println!("[SUCCESS] {}: File loaded and passed validation.", key); 
        } else {
            println!("[FAILED]  {}: Error: {:?}", key, record.error);
        }
    }

    Ok(())
}
